document.addEventListener("DOMContentLoaded",function(){var e=["日曜日","月曜日","火曜日","水曜日","木曜日","金曜日","土曜日"];function t(e){return e.getFullYear()+"年"+(e.getMonth()+1)+"月"+e.getDate()+"日"}function n(t){return e[t.getDay()]}function d(e,t){var n=t.getTime()-e.getTime();return Math.round(n/864e5)}var a=(new Date).toISOString().split("T")[0];document.getElementById("start-date").value=a,document.getElementById("base-date").value=a,document.getElementById("calc-diff-btn").addEventListener("click",function(){var e=document.getElementById("start-date").value,a=document.getElementById("end-date").value;if(e&&a){var o=new Date(e),l=new Date(a),u=Math.abs(d(o,l)),c=Math.floor(u/7),m=u%7;document.getElementById("diff-days").textContent=u+"日間",document.getElementById("diff-weeks").textContent=c+"週"+m+"日",document.getElementById("start-weekday").textContent=t(o)+"（"+n(o)+"）",document.getElementById("end-weekday").textContent=t(l)+"（"+n(l)+"）",document.getElementById("diff-result").hidden=!1}else alert("開始日と終了日を入力してください。")}),document.getElementById("calc-add-btn").addEventListener("click",function(){var e=document.getElementById("base-date").value,d=document.getElementById("add-days").value;if(e&&""!==d){var a=new Date(e),o=parseInt(d,10),l=new Date(a);l.setDate(l.getDate()+o);var u=o>=0?t(a)+"から"+o+"日後":t(a)+"から"+Math.abs(o)+"日前";document.getElementById("add-result-date").textContent=u+" = "+t(l),document.getElementById("add-result-weekday").textContent=n(l),document.getElementById("add-result").hidden=!1}else alert("基準日と日数を入力してください。")}),document.getElementById("calc-countdown-btn").addEventListener("click",function(){var e=document.getElementById("target-date").value;if(e){var a=new Date(e),o=new Date;o.setHours(0,0,0,0);var l=d(o,a),u=document.getElementById("countdown-days");l>0?(u.textContent="あと "+l+" 日",u.style.color="#22c55e"):0===l?(u.textContent="今日です！",u.style.color="#3b82f6"):(u.textContent=Math.abs(l)+" 日前に過ぎています",u.style.color="#ef4444"),document.getElementById("countdown-weekday").textContent=t(a)+"（"+n(a)+"）",document.getElementById("countdown-result").hidden=!1}else alert("目標日を入力してください。")})});